//! mesh_gossip — lightweight UDP gossip membership + liveness for the resilient
//! R1 mesh (docs/R1_RESILIENT_MESH.md, component 2).
//!
//! Each node advertises its stage (layer range) + data endpoint over UDP. A node
//! maintains a LIVE per-stage replica view, used to auto-populate the `/chain`
//! failover pool (replacing static `--next`). Design for shitty devices that brick:
//!   - DIRECT heartbeats refresh liveness (a peer is "alive" only if heard directly
//!     within the eviction window) -> a bricked node ages out everywhere.
//!   - RELAYED peer lists bootstrap DISCOVERY only (learn gossip endpoints); they do
//!     NOT mark a peer alive, so a relayed-but-dead node can't poison routing.
//!   - No central registry; converges from any shared seed.
//! Transport-agnostic: UDP works over localhost (tests) and WiFi (the room).

use bitwise::flow_frame;
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::net::UdpSocket;
use std::sync::{Arc, Mutex};
use std::time::{Duration, Instant};

/// Mesh-control stream id in the aeon FlowFrame family. Separate from 2002 so raw
/// node-membership heartbeats don't pollute Thoth's conscious stream. The mesh
/// instead *yields* a curated 2002 frame (see `hive_frame`) to keep the hive aware.
pub const MESH_GOSSIP_STREAM_ID: u16 = 2010;

/// The hive/conscious stream (Thoth/pneuma 2002 family). 2002 is the BRAIN channel —
/// it doesn't need the full topology, just "what's up": the mesh yields a small FOLD
/// status digest here so the hive has situational awareness, while the raw heartbeats
/// stay on 2010.
pub const HIVE_STREAM_ID: u16 = 2002;

/// A curated "what's up" digest projected onto 2002 — NOT the full peer list. Just
/// enough for the brain: how many nodes, what model, stage coverage, and health.
#[derive(Clone, Debug, Serialize, Deserialize)]
pub struct MeshSummary {
    pub model_id: String,
    /// Live nodes (incl. self).
    pub nodes: usize,
    /// Distinct stages as (layer_start, layer_end, replica_count), sorted.
    pub stages: Vec<(usize, usize, usize)>,
    /// Contiguous layers covered from 0 (== model layer count when the chain is whole).
    pub layers_covered: usize,
    /// "healthy" | "healthy (no redundancy)" | "degraded: <reason>".
    pub status: String,
    pub epoch_ms: u64,
}

/// Live system health a node advertises so the whole mesh can see who is jammed
/// without polling each `/status` endpoint. Rides the gossip heartbeat (carried on
/// `PeerInfo.status`), refreshed by the owner before each broadcast. All compact
/// integers/bools so the frame stays small; `#[serde(default)]` keeps the wire
/// back-compatible with pre-status peers (they decode as `NodeStatus::default()`).
#[derive(Clone, Debug, Default, Serialize, Deserialize, PartialEq)]
pub struct NodeStatus {
    /// MemAvailable in MiB (0 = unknown).
    pub free_mb: u64,
    /// MemTotal in MiB (0 = unknown).
    pub total_mb: u64,
    /// 1-minute load average × 1000 (integer; 0 = unknown).
    pub load_milli: u32,
    /// In-flight request count on the DATA plane right now — the truest jam signal.
    pub inflight: u32,
    /// Battery charge percent 0..=100 (255 = unknown / not a battery device).
    pub battery_pct: u8,
    /// On external power.
    pub charging: bool,
    /// Hottest thermal zone in deci-degrees C (temp × 10; 0 = unknown).
    pub temp_dc: i32,
    /// Owner-derived: this node is saturated and should be routed AROUND.
    pub jammed: bool,
}

#[derive(Clone, Debug, Serialize, Deserialize)]
pub struct PeerInfo {
    pub node_id: String,
    pub model_id: String,
    pub layer_start: usize,
    pub layer_end: usize,
    pub role: String,
    /// Advertised host (IP) for the DATA plane (fat-station HTTP / `/chain`).
    pub host: String,
    pub data_port: u16,
    pub gossip_port: u16,
    /// Node boot epoch (ms since UNIX) — lets peers detect a restart.
    pub epoch: u64,
    /// Live system health (RAM / load / battery / in-flight / jammed). Refreshed by
    /// the owner before each heartbeat; defaults for pre-status peers.
    #[serde(default)]
    pub status: NodeStatus,
}

impl PeerInfo {
    pub fn data_url(&self) -> String {
        format!("http://{}:{}", self.host, self.data_port)
    }
    pub fn gossip_addr(&self) -> String {
        format!("{}:{}", self.host, self.gossip_port)
    }
}

#[derive(Serialize, Deserialize)]
struct GossipPacket {
    from: PeerInfo,
    /// The sender's live view — receivers use it for endpoint DISCOVERY only.
    peers: Vec<PeerInfo>,
}

/// Encode a gossip packet as a house `flow_frame::FlowFrame` (the aeon wire) on the
/// mesh-control stream. Gossip is a VENT of membership state.
fn encode_frame(pkt: &GossipPacket, sequence: u32) -> Option<Vec<u8>> {
    let payload = serde_json::to_vec(pkt).ok()?;
    Some(flow_frame::encode(&flow_frame::FlowFrame {
        stream_id: MESH_GOSSIP_STREAM_ID,
        sequence,
        flags: flow_frame::VENT,
        payload,
    }))
}

/// Decode a gossip packet from a house FlowFrame; ignores frames on other streams.
fn decode_frame(buf: &[u8]) -> Option<GossipPacket> {
    let (frame, _consumed) = flow_frame::decode(buf)?;
    if frame.stream_id != MESH_GOSSIP_STREAM_ID {
        return None;
    }
    serde_json::from_slice::<GossipPacket>(&frame.payload).ok()
}

/// Build a stand-alone DIRECT-heartbeat FlowFrame advertising `peer` (no relayed peer
/// list). External producers — notably the protocol69 RF-gossip bridge (`rf_beacon` +
/// `bin/rf-gossip-bridge`) — use this to inject an RF-discovered node into a running
/// fat-station's stream-2010 registry: send the bytes as a UDP datagram to the node's
/// gossip port and its recv loop `note_direct`s the advertised peer (inserting it as
/// `admitted: false`, so it still passes qspec before routing).
pub fn peer_heartbeat_frame(peer: &PeerInfo, sequence: u32) -> Vec<u8> {
    encode_frame(
        &GossipPacket {
            from: peer.clone(),
            peers: Vec::new(),
        },
        sequence,
    )
    .unwrap_or_default()
}

/// Decode the advertised peer (`from`) out of a mesh-stream heartbeat FlowFrame. `None`
/// for other streams or malformed payloads. Symmetric with `peer_heartbeat_frame`.
pub fn decode_heartbeat_frame(buf: &[u8]) -> Option<PeerInfo> {
    decode_frame(buf).map(|pkt| pkt.from)
}

struct Entry {
    info: PeerInfo,
    last_seen: Instant,
    /// Component 4: has this peer passed the PARIS qspec probe? Only admitted peers
    /// enter the routing pool when admission is required, so a corrupt/lying node
    /// can't poison the mesh. Preserved across heartbeats; (re)set by the prober.
    admitted: bool,
}

/// Pure RAM-aware stage election over an EXPLICIT membership snapshot. Single source of
/// truth for the election: the `recommend_stage` method delegates here, and the host-side
/// `mesh-elect` tool (catch-and-release provisioning) calls it with the peers it pulled
/// from a seed's `/mesh/peers`. `peers` should be the live membership (incl. self).
/// Returns the stage a NEW node of `my_capacity_mb` should take, or `None` if every stage
/// already has `>= target_replicas` (mesh fully redundant — no new stage needed).
pub fn recommend_stage_from(
    peers: &[PeerInfo],
    model_id: &str,
    stages: &[(usize, usize)],
    my_capacity_mb: u64,
    target_replicas: usize,
) -> Option<(usize, usize)> {
    if stages.is_empty() {
        return None;
    }
    // Count live replicas for each stage index (model-scoped).
    let mut replica_count: Vec<usize> = vec![0; stages.len()];
    for peer in peers {
        if peer.model_id != model_id {
            continue;
        }
        for (i, &(ls, le)) in stages.iter().enumerate() {
            if peer.layer_start == ls && peer.layer_end == le {
                replica_count[i] += 1;
            }
        }
    }
    // Minimum replica count among under-replicated stages (None -> all at target).
    let min_replicas = replica_count
        .iter()
        .copied()
        .filter(|&c| c < target_replicas)
        .min()?;
    // Candidates that share the minimum replica count.
    let candidates: Vec<(usize, usize)> = stages
        .iter()
        .zip(replica_count.iter())
        .filter(|(_, &c)| c == min_replicas)
        .map(|(&(ls, le), _)| (ls, le))
        .collect();
    // Tie-break by capacity: a node that can hold a stage prefers the LARGEST it fits;
    // one that can't prefers the smallest. Heuristic ~1 GB per stage layer-count unit.
    candidates.into_iter().max_by_key(|&(ls, le)| {
        let size = le.saturating_sub(ls);
        let fits = my_capacity_mb >= 1024 * size as u64;
        if fits {
            size as i64
        } else {
            -(size as i64)
        }
    })
}

pub struct MeshRegistry {
    self_info: PeerInfo,
    /// node_id -> directly-confirmed-alive entry.
    peers: Mutex<HashMap<String, Entry>>,
    /// Gossip endpoints to send to (seeds + every discovered peer).
    send_to: Mutex<Vec<String>>,
    eviction: Duration,
    /// When true, `next_stage_pool` returns only admitted peers (the prober gates
    /// them). Off by default = admit-all (back-compat).
    admission_required: std::sync::atomic::AtomicBool,
    /// Our own live health, merged into `self_info` before each heartbeat. The owner
    /// (fat-station) refreshes this with `set_self_status`; the sender broadcasts it.
    self_status: Mutex<NodeStatus>,
}

impl MeshRegistry {
    /// Peers heard DIRECTLY within the eviction window.
    pub fn live_peers(&self) -> Vec<PeerInfo> {
        let now = Instant::now();
        let m = self.peers.lock().unwrap();
        m.values()
            .filter(|e| now.duration_since(e.last_seen) < self.eviction)
            .map(|e| e.info.clone())
            .collect()
    }

    /// Refresh our advertised health. fat-station calls this from a background
    /// sampler so the NEXT heartbeat carries fresh RAM / load / in-flight / jam.
    pub fn set_self_status(&self, status: NodeStatus) {
        *self.self_status.lock().unwrap() = status;
    }

    /// Our last-sampled health (what the next heartbeat will advertise).
    pub fn self_status(&self) -> NodeStatus {
        self.self_status.lock().unwrap().clone()
    }

    /// Live data URLs of replicas serving the NEXT stage (their `layer_start` ==
    /// my `layer_end`, same model). This IS the `/chain` failover pool. When
    /// admission is required, only admitted (PARIS-probed) peers are returned.
    pub fn next_stage_pool(&self) -> Vec<String> {
        let me = &self.self_info;
        let require = self
            .admission_required
            .load(std::sync::atomic::Ordering::Relaxed);
        let now = Instant::now();
        // Partition into healthy vs jammed candidates so the chain routes AROUND
        // saturated nodes (gossiped `status.jammed`); fall back to jammed peers only
        // if every replica of the next stage is jammed — degraded beats dropped.
        let mut healthy: Vec<String> = Vec::new();
        let mut jammed: Vec<String> = Vec::new();
        for e in self.peers.lock().unwrap().values() {
            if now.duration_since(e.last_seen) >= self.eviction {
                continue;
            }
            if e.info.node_id == me.node_id
                || e.info.model_id != me.model_id
                || e.info.layer_start != me.layer_end
                || (require && !e.admitted)
            {
                continue;
            }
            if e.info.status.jammed {
                jammed.push(e.info.data_url());
            } else {
                healthy.push(e.info.data_url());
            }
        }
        if healthy.is_empty() {
            jammed
        } else {
            healthy
        }
    }

    /// Next-stage peers that still need a PARIS probe (the prober calls this).
    pub fn unadmitted_next_stage(&self) -> Vec<PeerInfo> {
        let me = &self.self_info;
        let now = Instant::now();
        self.peers
            .lock()
            .unwrap()
            .values()
            .filter(|e| now.duration_since(e.last_seen) < self.eviction)
            .filter(|e| {
                !e.admitted
                    && e.info.node_id != me.node_id
                    && e.info.model_id == me.model_id
                    && e.info.layer_start == me.layer_end
            })
            .map(|e| e.info.clone())
            .collect()
    }

    pub fn set_admission_required(&self, on: bool) {
        self.admission_required
            .store(on, std::sync::atomic::Ordering::Relaxed);
    }

    /// Record a peer's PARIS-probe verdict.
    pub fn set_admitted(&self, node_id: &str, ok: bool) {
        if let Some(e) = self.peers.lock().unwrap().get_mut(node_id) {
            e.admitted = ok;
        }
    }

    /// A direct heartbeat from `p`: confirm liveness + learn its gossip endpoint.
    /// Admission verdict is PRESERVED across heartbeats (a known-good peer stays
    /// admitted; only the prober changes it).
    fn note_direct(&self, p: &PeerInfo) {
        if p.node_id == self.self_info.node_id {
            return;
        }
        let mut m = self.peers.lock().unwrap();
        match m.get_mut(&p.node_id) {
            Some(e) => {
                e.info = p.clone();
                e.last_seen = Instant::now();
            }
            None => {
                m.insert(
                    p.node_id.clone(),
                    Entry {
                        info: p.clone(),
                        last_seen: Instant::now(),
                        admitted: false,
                    },
                );
            }
        }
        drop(m);
        self.add_endpoint(&p.gossip_addr());
    }

    /// Discovery only: learn a gossip endpoint (does NOT mark the peer alive — it
    /// must heartbeat directly to enter the routing pool).
    fn learn_endpoint(&self, p: &PeerInfo) {
        if p.node_id != self.self_info.node_id {
            self.add_endpoint(&p.gossip_addr());
        }
    }

    fn add_endpoint(&self, addr: &str) {
        let mut s = self.send_to.lock().unwrap();
        if !s.iter().any(|e| e == addr) {
            s.push(addr.to_string());
        }
    }

    pub fn self_info(&self) -> &PeerInfo {
        &self.self_info
    }

    /// The "what's up" digest for the brain (2002): node count, per-stage replica
    /// counts, contiguous layer coverage, and a one-line health verdict.
    pub fn mesh_summary(&self) -> MeshSummary {
        let me = &self.self_info;
        let mut live = self.live_peers();
        live.push(me.clone());
        let nodes = live.len();
        let mut counts: std::collections::BTreeMap<(usize, usize), usize> =
            std::collections::BTreeMap::new();
        for p in &live {
            if p.model_id == me.model_id {
                *counts.entry((p.layer_start, p.layer_end)).or_insert(0) += 1;
            }
        }
        let stages: Vec<(usize, usize, usize)> =
            counts.iter().map(|((s, e), c)| (*s, *e, *c)).collect();
        // Greedy contiguous coverage from layer 0.
        let mut cursor = 0usize;
        loop {
            let next = counts
                .keys()
                .filter(|(s, _)| *s == cursor)
                .map(|(_, e)| *e)
                .max();
            match next {
                Some(e) if e > cursor => cursor = e,
                _ => break,
            }
        }
        let layers_covered = cursor;
        let max_end = stages.iter().map(|(_, e, _)| *e).max().unwrap_or(0);
        let min_replicas = stages.iter().map(|(_, _, c)| *c).min().unwrap_or(0);
        let status = if stages.is_empty() {
            "degraded: no nodes".to_string()
        } else if layers_covered < max_end {
            format!("degraded: gap at layer {}", layers_covered)
        } else if min_replicas < 2 {
            "healthy (no redundancy)".to_string()
        } else {
            "healthy".to_string()
        };
        MeshSummary {
            model_id: me.model_id.clone(),
            nodes,
            stages,
            layers_covered,
            status,
            epoch_ms: now_epoch_ms(),
        }
    }

    /// Recommend which stage a joining node should take to best balance the mesh.
    ///
    /// `stages`          — the full stage slice: `[(layer_start, layer_end), ...]`.
    /// `my_capacity_mb`  — the joining node's RAM in MB (capacity argument only; we
    ///                     never read or modify `PeerInfo` fields for this).
    /// `target_replicas` — desired replica count per stage; once all stages are at or
    ///                     above this level the mesh is fully redundant.
    ///
    /// Election logic: scan live peers (same `model_id`) and count how many replicas
    /// each stage in `stages` already has; recommend the stage with the fewest replicas
    /// below `target_replicas` (most under-replicated). Ties are broken by capacity: a
    /// larger `my_capacity_mb` favours the largest under-replicated stage (max
    /// `end - start` layers), while a smaller capacity favours the smallest — the
    /// heuristic used is `my_capacity_mb >= 1024 * (end - start)` (roughly 1 GB per
    /// 12-layer shard on a ~7 B model). Returns `None` when every stage already meets
    /// `target_replicas`.
    pub fn recommend_stage(
        &self,
        stages: &[(usize, usize)],
        my_capacity_mb: u64,
        target_replicas: usize,
    ) -> Option<(usize, usize)> {
        recommend_stage_from(
            &self.live_peers(),
            &self.self_info.model_id,
            stages,
            my_capacity_mb,
            target_replicas,
        )
    }

    /// A 2002 (brain/hive) FlowFrame carrying the "what's up" digest — FOLD-flagged
    /// (a fold of mesh state into the conscious stream). The mesh yields this so the
    /// brain stays aware without ever seeing the raw 2010 heartbeats.
    pub fn hive_frame(&self) -> Vec<u8> {
        let payload = serde_json::to_vec(&self.mesh_summary()).unwrap_or_default();
        flow_frame::encode(&flow_frame::FlowFrame {
            stream_id: HIVE_STREAM_ID,
            sequence: now_epoch_ms() as u32,
            flags: flow_frame::FOLD,
            payload,
        })
    }
}

/// Best-effort local IP for the DATA plane (the outbound-interface address, i.e.
/// the WiFi IP when WiFi is the route). Override with an explicit host if needed.
pub fn detect_local_ip() -> Option<String> {
    let s = UdpSocket::bind("0.0.0.0:0").ok()?;
    s.connect("8.8.8.8:80").ok()?;
    s.local_addr().ok().map(|a| a.ip().to_string())
}

pub fn now_epoch_ms() -> u64 {
    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_millis() as u64)
        .unwrap_or(0)
}

/// Start the gossip threads (send + receive) and return the shared registry.
/// `seeds` are gossip endpoints ("ip:port") to bootstrap from.
pub fn start_gossip(
    self_info: PeerInfo,
    seeds: Vec<String>,
    interval: Duration,
    eviction: Duration,
) -> std::io::Result<Arc<MeshRegistry>> {
    let reg = Arc::new(MeshRegistry {
        self_status: Mutex::new(self_info.status.clone()),
        self_info: self_info.clone(),
        peers: Mutex::new(HashMap::new()),
        send_to: Mutex::new(seeds),
        eviction,
        admission_required: std::sync::atomic::AtomicBool::new(false),
    });
    let sock = Arc::new(UdpSocket::bind(("0.0.0.0", self_info.gossip_port))?);
    sock.set_read_timeout(Some(Duration::from_millis(500))).ok();

    // Receiver: confirm direct senders + learn relayed endpoints.
    {
        let reg = Arc::clone(&reg);
        let sock = Arc::clone(&sock);
        std::thread::spawn(move || {
            let mut buf = vec![0u8; 64 * 1024];
            loop {
                match sock.recv_from(&mut buf) {
                    Ok((n, _src)) => {
                        if let Some(pkt) = decode_frame(&buf[..n]) {
                            reg.note_direct(&pkt.from);
                            for p in &pkt.peers {
                                reg.learn_endpoint(p);
                            }
                        }
                    }
                    Err(_) => {} // read timeout — loop
                }
            }
        });
    }
    // Sender: broadcast our heartbeat + live view to all known gossip endpoints.
    {
        let reg = Arc::clone(&reg);
        let sock = Arc::clone(&sock);
        let me = self_info;
        std::thread::spawn(move || {
            let mut sequence: u32 = 0;
            loop {
                // Merge our freshest health into the heartbeat so peers learn our
                // RAM / load / in-flight / jam state without a separate poll.
                let mut from = me.clone();
                from.status = reg.self_status.lock().unwrap().clone();
                let pkt = GossipPacket {
                    from,
                    peers: reg.live_peers(),
                };
                if let Some(bytes) = encode_frame(&pkt, sequence) {
                    let targets = reg.send_to.lock().unwrap().clone();
                    for t in targets {
                        let _ = sock.send_to(&bytes, &t);
                    }
                }
                sequence = sequence.wrapping_add(1);
                std::thread::sleep(interval);
            }
        });
    }
    Ok(reg)
}

#[cfg(test)]
mod tests {
    use super::*;

    fn info(id: &str, ls: usize, le: usize, gp: u16) -> PeerInfo {
        PeerInfo {
            node_id: id.into(),
            model_id: "m".into(),
            layer_start: ls,
            layer_end: le,
            role: "mid".into(),
            host: "127.0.0.1".into(),
            data_port: 9000,
            gossip_port: gp,
            epoch: 0,
            status: NodeStatus::default(),
        }
    }

    #[test]
    fn next_stage_pool_matches_adjacent_stage_only() {
        // self serves [0,12); a peer serving [12,24) is the next stage, [24,36) is not.
        let reg = MeshRegistry {
            self_info: info("self", 0, 12, 7000),
            peers: Mutex::new(HashMap::new()),
            send_to: Mutex::new(vec![]),
            eviction: Duration::from_secs(8),
            admission_required: std::sync::atomic::AtomicBool::new(false),
            self_status: Mutex::new(NodeStatus::default()),
        };
        reg.note_direct(&PeerInfo {
            data_port: 9001,
            ..info("A", 12, 24, 7001)
        });
        reg.note_direct(&PeerInfo {
            data_port: 9002,
            ..info("B", 24, 36, 7002)
        });
        let pool = reg.next_stage_pool();
        assert_eq!(
            pool,
            vec!["http://127.0.0.1:9001".to_string()],
            "only the [12,24) replica"
        );
    }

    #[test]
    fn evicts_stale_peers() {
        let reg = MeshRegistry {
            self_info: info("self", 0, 12, 7010),
            peers: Mutex::new(HashMap::new()),
            send_to: Mutex::new(vec![]),
            eviction: Duration::from_millis(50),
            admission_required: std::sync::atomic::AtomicBool::new(false),
            self_status: Mutex::new(NodeStatus::default()),
        };
        reg.note_direct(&info("A", 12, 24, 7011));
        assert_eq!(reg.next_stage_pool().len(), 1);
        std::thread::sleep(Duration::from_millis(80));
        assert_eq!(
            reg.next_stage_pool().len(),
            0,
            "stale peer evicted from the pool"
        );
    }

    #[test]
    fn gossip_rides_a_flowframe_on_the_mesh_stream() {
        let pkt = GossipPacket {
            from: info("A", 0, 12, 7100),
            peers: vec![info("B", 12, 24, 7101)],
        };
        let bytes = encode_frame(&pkt, 7).unwrap();
        // it really is a house FlowFrame on the mesh stream
        let (frame, _) = flow_frame::decode(&bytes).unwrap();
        assert_eq!(frame.stream_id, MESH_GOSSIP_STREAM_ID);
        // round-trips back to the packet
        let got = decode_frame(&bytes).unwrap();
        assert_eq!(got.from.node_id, "A");
        assert_eq!(got.peers.len(), 1);
        // a frame on a different stream (e.g. 2002 conscious) is ignored
        let other = flow_frame::encode(&flow_frame::FlowFrame {
            stream_id: 2002,
            sequence: 0,
            flags: 0,
            payload: b"not-mesh".to_vec(),
        });
        assert!(decode_frame(&other).is_none());
    }

    #[test]
    fn hive_frame_is_a_2002_fold_status_digest() {
        // self [0,12) + peer A [12,24) -> 24 layers covered, 1 replica each.
        let reg = MeshRegistry {
            self_info: info("self", 0, 12, 7200),
            peers: Mutex::new(HashMap::new()),
            send_to: Mutex::new(vec![]),
            eviction: Duration::from_secs(8),
            admission_required: std::sync::atomic::AtomicBool::new(false),
            self_status: Mutex::new(NodeStatus::default()),
        };
        reg.note_direct(&info("A", 12, 24, 7201));
        let bytes = reg.hive_frame();
        let (f, _) = flow_frame::decode(&bytes).unwrap();
        assert_eq!(
            f.stream_id, HIVE_STREAM_ID,
            "yields on the 2002 brain channel"
        );
        assert_eq!(
            f.flags,
            flow_frame::FOLD,
            "a fold of mesh state into consciousness"
        );
        let s: MeshSummary = serde_json::from_slice(&f.payload).unwrap();
        assert_eq!(s.nodes, 2);
        assert_eq!(s.layers_covered, 24, "self+A tile 0..24");
        assert!(
            s.status.starts_with("healthy"),
            "covered, just no redundancy: {}",
            s.status
        );
        // it's a DIGEST, not the full peer list — no PeerInfo array in the payload
        assert!(!String::from_utf8_lossy(&f.payload).contains("gossip_port"));
    }

    #[test]
    fn relayed_peers_are_discovered_not_trusted_alive() {
        let reg = MeshRegistry {
            self_info: info("self", 0, 12, 7020),
            peers: Mutex::new(HashMap::new()),
            send_to: Mutex::new(vec![]),
            eviction: Duration::from_secs(8),
            admission_required: std::sync::atomic::AtomicBool::new(false),
            self_status: Mutex::new(NodeStatus::default()),
        };
        // learned via relay only -> endpoint known but NOT in the live pool
        reg.learn_endpoint(&info("A", 12, 24, 7021));
        assert_eq!(
            reg.next_stage_pool().len(),
            0,
            "relayed peer not routed until direct heartbeat"
        );
        assert!(reg
            .send_to
            .lock()
            .unwrap()
            .iter()
            .any(|e| e == "127.0.0.1:7021"));
    }

    #[test]
    fn admission_gates_the_routing_pool() {
        let reg = MeshRegistry {
            self_info: info("self", 0, 12, 7300),
            peers: Mutex::new(HashMap::new()),
            send_to: Mutex::new(vec![]),
            eviction: Duration::from_secs(8),
            admission_required: std::sync::atomic::AtomicBool::new(false),
            self_status: Mutex::new(NodeStatus::default()),
        };
        reg.note_direct(&PeerInfo {
            data_port: 9001,
            ..info("A", 12, 24, 7301)
        });
        assert_eq!(reg.next_stage_pool().len(), 1, "admission off -> routable");
        // require admission -> unadmitted peer is gated OUT of routing
        reg.set_admission_required(true);
        assert_eq!(
            reg.next_stage_pool().len(),
            0,
            "unadmitted peer can't be routed to"
        );
        assert_eq!(
            reg.unadmitted_next_stage().len(),
            1,
            "but it's a probe candidate"
        );
        // PARIS probe passes -> admit -> routable
        reg.set_admitted("A", true);
        assert_eq!(
            reg.next_stage_pool(),
            vec!["http://127.0.0.1:9001".to_string()]
        );
        // a later heartbeat must NOT reset admission
        reg.note_direct(&PeerInfo {
            data_port: 9001,
            ..info("A", 12, 24, 7301)
        });
        assert_eq!(
            reg.next_stage_pool().len(),
            1,
            "admission survives heartbeats"
        );
    }

    // ---- recommend_stage tests -----------------------------------------------

    fn make_reg(self_ls: usize, self_le: usize, gp: u16) -> MeshRegistry {
        MeshRegistry {
            self_info: info("self", self_ls, self_le, gp),
            peers: Mutex::new(HashMap::new()),
            send_to: Mutex::new(vec![]),
            eviction: Duration::from_secs(60),
            admission_required: std::sync::atomic::AtomicBool::new(false),
            self_status: Mutex::new(NodeStatus::default()),
        }
    }

    #[test]
    fn recommend_stage_empty_mesh_returns_first_stage() {
        // No live peers at all -> every stage has 0 replicas -> recommend one.
        let stages = [(0usize, 12usize), (12, 24)];
        let reg = make_reg(0, 12, 8000);
        let got = reg.recommend_stage(&stages, 2048, 2).unwrap();
        // Both have 0 replicas; 2048 MB can hold a 12-layer shard (1024*12 = 12288 MB?
        // No — heuristic is 1024 * size; size=12 => 12288 MB required which is > 2048.
        // So fits=false for both. Both rank by -(12) = -12 tie -> max_by_key picks the
        // first candidate that survives (deterministic for equal keys via last wins in
        // Rust's max_by_key). Either stage is acceptable; just ensure it's in the set.
        assert!(
            stages.contains(&got),
            "recommended stage must be one of the input stages"
        );
    }

    #[test]
    fn recommend_stage_covered_stage_picks_uncovered() {
        // Stage (0,12) has 1 replica already; stage (12,24) has 0 -> pick (12,24).
        let stages = [(0usize, 12usize), (12, 24)];
        let reg = make_reg(99, 99, 8010); // self not in any stage
        reg.note_direct(&info("A", 0, 12, 8011));
        let got = reg.recommend_stage(&stages, 4096, 2).unwrap();
        assert_eq!(got, (12, 24), "should pick the uncovered stage");
    }

    #[test]
    fn recommend_stage_all_at_target_returns_none() {
        // Both stages already have target_replicas=1 replica -> None.
        let stages = [(0usize, 12usize), (12, 24)];
        let reg = make_reg(99, 99, 8020);
        reg.note_direct(&info("A", 0, 12, 8021));
        reg.note_direct(&info("B", 12, 24, 8022));
        let got = reg.recommend_stage(&stages, 4096, 1);
        assert!(got.is_none(), "fully covered mesh must return None");
    }

    #[test]
    fn recommend_stage_capacity_tiebreak_large_capacity_picks_larger_stage() {
        // Both stages have 0 replicas (tied). Large capacity -> prefer larger stage.
        // Stage sizes: (0,8)=8 layers, (8,24)=16 layers.
        // Large enough capacity to hold 16-layer stage: 1024*16 = 16384 MB.
        let stages = [(0usize, 8usize), (8, 24)];
        let reg = make_reg(99, 99, 8030);
        // 20000 MB > 16384 MB -> fits both -> rank by size -> (8,24) wins.
        let got = reg.recommend_stage(&stages, 20_000, 2).unwrap();
        assert_eq!(
            got,
            (8, 24),
            "large capacity should prefer the bigger stage"
        );
    }

    #[test]
    fn recommend_stage_capacity_tiebreak_small_capacity_picks_smaller_stage() {
        // Both stages 0 replicas. Small capacity can't hold the 16-layer stage.
        // 1024*16=16384 MB needed; only 1024 MB available -> fits=false for (8,24).
        // (0,8)=8 layers needs 8192 MB; 1024 < 8192 -> also fits=false.
        // Both fits=false -> rank by -size -> -(8)=-8 vs -(16)=-16 -> -8 > -16 -> (0,8).
        let stages = [(0usize, 8usize), (8, 24)];
        let reg = make_reg(99, 99, 8040);
        let got = reg.recommend_stage(&stages, 1024, 2).unwrap();
        assert_eq!(
            got,
            (0, 8),
            "small capacity should prefer the smaller stage"
        );
    }
}
